frappe.listview_settings['Loading Sheet'] = {
    onload: function(listview) {
        listview.page.add_inner_button('Create Dispatch Sheet', () => {
            const selected = listview.get_checked_items().map(row => row.name);
            if (!selected.length) {
                frappe.msgprint("Please select at least one Loading Sheet.");
                return;
            }

            frappe.call({
                method: "create_dispatch_sheet_from_loading_sheets",
                args: {
                    loading_sheets: JSON.stringify(selected)
                },
                callback: function(r) {
                    if (r.message) {
                        frappe.set_route("Form", "Dispatch Sheet", r.message);
                    }
                }
            });
        });
    }
};

frappe.ui.form.on('Stock Entry', {
  on_submit: function(frm) {
    if (frm.doc.purpose === 'Manufacture') {
      frappe.call({
        method: 'create_batch_for_qr_codes',
        args: {
          name: frm.doc.name,  
          item_code: frm.doc.items[0].item_code,
          qr_codes: frm.doc.table_cnlu.map(row => row.qr_code),
          manufacture_date: frappe.datetime.get_today()
        },
        callback: function(r) {
          if (r.message) {
            frm.doc.items[0].batch_no = r.message;
            frm.refresh_field('items');
          }
        }
      });
    }
  }
});

frappe.listview_settings['Loading Sheet'] = {
    onload: function(listview) {
        listview.page.add_inner_button('Create Dispatch Sheet', () => {
            const selected = listview.get_checked_items().map(row => row.name);
            if (!selected.length) {
