                },
                callback: function(r) {
                    if (r.message) {
                        frappe.set_route("Form", "Dispatch Sheet", r.message);
                    }
                }
            });
        });
    }
};

frappe.listview_settings['Delivery Note'] = {
    onload: function (listview) {
        listview.page.add_inner_button(__('Create Loading Sheet'), function () {
            var selected_docs = listview.get_checked_items();
            if (selected_docs.length > 0) {
                var delivery_notes = selected_docs.map(doc => doc.name);
                create_loading_sheet_with_delivery_notes(delivery_notes);
            } else {
                frappe.msgprint(__('Please select Delivery Notes.'));
            }
        });
    }
};

function create_loading_sheet_with_delivery_notes(delivery_notes) {
    frappe.model.with_doctype('Loading Sheet', function () {
        var loading_sheet_doc = frappe.model.get_new_doc('Loading Sheet');

        loading_sheet_doc.date = frappe.datetime.get_today();

        // Add delivery notes to the loading sheet document
        loading_sheet_doc.delivery_notes = delivery_notes.join(', ');

        // Load items and customer details from selected delivery notes
        load_items_and_customer_details(loading_sheet_doc, delivery_notes);
    });
}

function load_items_and_customer_details(loading_sheet_doc, delivery_notes) {
    var items = {};
    var customer_totals = {};
    var scanned_items = {};

    var requests = delivery_notes.map(note => {
        return frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Delivery Note',
                name: note
            }
        }).then(response => {
            if (response.message) {
                var delivery_note = response.message;
                var customer = delivery_note.customer;
                var customer_name = delivery_note.customer_name;
                var grand_total = delivery_note.grand_total;

                if (!customer_totals[customer]) {
                    customer_totals[customer] = {
                        customer_name: customer_name,
                        total_amount: grand_total,
                        delivery_notes: [note]
                    };
                } else {
                    customer_totals[customer].total_amount += grand_total;
                    customer_totals[customer].delivery_notes.push(note);
                }

                // For each item in delivery note
                var item_promises = delivery_note.items.map(item => {
                    var key = item.item_code;

                    // Collect totals for all loading sheet items
                    if (!items[key]) {
                        items[key] = {
                            item_code: item.item_code,
                            item_name: item.item_name,
                            qty: item.qty,
                            rate: item.rate,
                            amount: item.rate * item.qty
                        };
                    } else {
                        items[key].qty += item.qty;
                        items[key].amount += item.rate * item.qty;
                    }

                    // Check if the item is marked as scanned
                    return frappe.call({
                        method: 'frappe.client.get_value',
                        args: {
                            doctype: 'Item',
                            filters: { name: item.item_code },
                            fieldname: ['custom_is_scanned']
                        }
                    }).then(item_res => {
                        if (item_res.message && item_res.message.custom_is_scanned) {
                            if (!scanned_items[key]) {
                                scanned_items[key] = {
                                    item_code: item.item_code,
                                    item_name: item.item_name,
                                    qty: item.qty
                                };
                            } else {
                                scanned_items[key].qty += item.qty;
                            }
                        }
                    });
                });

                return Promise.all(item_promises);
            }
        }).catch(error => {
            console.error('Error fetching Delivery Note:', note, error);
            frappe.msgprint(__('Failed to fetch details for Delivery Note: {0}', [note]));
        });
    });

    Promise.all(requests).then(() => {
        if (Object.keys(items).length === 0) {
            frappe.msgprint(__('No items found in selected Delivery Notes.'));
            return;
        }

        // Add items to loading_sheet_items table
        // Add items to loading_sheet_items table
        for (let key in items) {
            if (items.hasOwnProperty(key)) {
                let item = items[key];
                let new_row = frappe.model.add_child(loading_sheet_doc, 'loading_sheet_items');
                new_row.item_code = item.item_code;
                new_row.item_name = item.item_name;
                new_row.qty = item.qty;
                new_row.rate = item.rate;
                new_row.amount = item.amount;
            }
        }

        // Add items to scan_items table (only if custom_is_scanned = 1)
        for (let key in scanned_items) {
            if (scanned_items.hasOwnProperty(key)) {
                let scan_item = scanned_items[key];
                let scan_row = frappe.model.add_child(loading_sheet_doc, 'scan_items');
                scan_row.item_code = scan_item.item_code;
                scan_row.item_name = scan_item.item_name;
                scan_row.qty = scan_item.qty;
            }
        }


        // Add customer details to customer_details table
        for (var customer in customer_totals) {
            if (customer_totals.hasOwnProperty(customer)) {
                var customer_detail_row = frappe.model.add_child(loading_sheet_doc, 'customer_details');
                customer_detail_row.customer_name = customer_totals[customer].customer_name;
                customer_detail_row.delivery_notes = customer_totals[customer].delivery_notes.join(', ');
                customer_detail_row.total_amount = customer_totals[customer].total_amount;
            }
        }

        // Route to new Loading Sheet
        frappe.set_route('Form', loading_sheet_doc.doctype, loading_sheet_doc.name);
    }).catch(error => {
        console.error('Error processing Delivery Note Items and Customer Details:', error);
        frappe.msgprint(__('An error occurred while processing Delivery Note items and customer details.'));
    });
}
